CREATE SCHEMA IF NOT EXISTS ecommerce;

CREATE SEQUENCE ecommerce.users_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.addresses_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.categories_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.products_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.product_images_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.carts_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.cart_items_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.orders_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.order_items_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.payments_id_seq START 1 INCREMENT 1;

CREATE SEQUENCE ecommerce.reviews_id_seq START 1 INCREMENT 1;

CREATE TABLE ecommerce.users (
    id BIGINT DEFAULT nextval('ecommerce.users_id_seq') PRIMARY KEY,
    first_name VARCHAR(100) NOT NULL,
    last_name VARCHAR(100) NOT NULL,
    email VARCHAR(255) NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    phone VARCHAR(20),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_verified BOOLEAN NOT NULL DEFAULT FALSE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.addresses (
    id BIGINT DEFAULT nextval('ecommerce.addresses_id_seq') PRIMARY KEY,
    user_id BIGINT NOT NULL REFERENCES ecommerce.users(id) ON DELETE CASCADE,
    label VARCHAR(50),
    street_line1 VARCHAR(255) NOT NULL,
    street_line2 VARCHAR(255),
    city VARCHAR(100) NOT NULL,
    state VARCHAR(100),
    postal_code VARCHAR(20) NOT NULL,
    country VARCHAR(100) NOT NULL,
    is_default BOOLEAN NOT NULL DEFAULT FALSE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.categories (
    id BIGINT DEFAULT nextval('ecommerce.categories_id_seq') PRIMARY KEY,
    name VARCHAR(150) NOT NULL UNIQUE,
    slug VARCHAR(150) NOT NULL UNIQUE,
    description TEXT,
    parent_id BIGINT REFERENCES ecommerce.categories(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.products (
    id BIGINT DEFAULT nextval('ecommerce.products_id_seq') PRIMARY KEY,
    category_id BIGINT REFERENCES ecommerce.categories(id) ON DELETE SET NULL,
    name VARCHAR(255) NOT NULL,
    slug VARCHAR(255) NOT NULL UNIQUE,
    description TEXT,
    price NUMERIC(12, 2) NOT NULL CHECK (price >= 0),
    stock_quantity INT NOT NULL DEFAULT 0 CHECK (stock_quantity >= 0),
    sku VARCHAR(100) UNIQUE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.product_images (
    id BIGINT DEFAULT nextval('ecommerce.product_images_id_seq') PRIMARY KEY,
    product_id BIGINT NOT NULL REFERENCES ecommerce.products(id) ON DELETE CASCADE,
    image_url TEXT NOT NULL,
    alt_text VARCHAR(255),
    is_primary BOOLEAN NOT NULL DEFAULT FALSE,
    sort_order INT NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.carts (
    id BIGINT DEFAULT nextval('ecommerce.carts_id_seq') PRIMARY KEY,
    user_id BIGINT REFERENCES ecommerce.users(id) ON DELETE CASCADE,
    session_id VARCHAR(255),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT chk_cart_owner CHECK (user_id IS NOT NULL OR session_id IS NOT NULL)
);

CREATE TABLE ecommerce.cart_items (
    id BIGINT DEFAULT nextval('ecommerce.cart_items_id_seq') PRIMARY KEY,
    cart_id BIGINT NOT NULL REFERENCES ecommerce.carts(id) ON DELETE CASCADE,
    product_id BIGINT NOT NULL REFERENCES ecommerce.products(id) ON DELETE CASCADE,
    quantity INT NOT NULL DEFAULT 1 CHECK (quantity > 0),
    added_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_cart_product UNIQUE (cart_id, product_id)
);

CREATE TABLE ecommerce.orders (
    id BIGINT DEFAULT nextval('ecommerce.orders_id_seq') PRIMARY KEY,
    user_id BIGINT NOT NULL REFERENCES ecommerce.users(id) ON DELETE RESTRICT,
    shipping_address_id BIGINT REFERENCES ecommerce.addresses(id) ON DELETE SET NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','confirmed','processing','shipped','delivered','cancelled','refunded')),
    subtotal NUMERIC(12, 2) NOT NULL DEFAULT 0 CHECK (subtotal >= 0),
    shipping_cost NUMERIC(12, 2) NOT NULL DEFAULT 0 CHECK (shipping_cost >= 0),
    tax NUMERIC(12, 2) NOT NULL DEFAULT 0 CHECK (tax >= 0),
    total NUMERIC(12, 2) NOT NULL DEFAULT 0 CHECK (total >= 0),
    notes TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.order_items (
    id BIGINT DEFAULT nextval('ecommerce.order_items_id_seq') PRIMARY KEY,
    order_id BIGINT NOT NULL REFERENCES ecommerce.orders(id) ON DELETE CASCADE,
    product_id BIGINT REFERENCES ecommerce.products(id) ON DELETE SET NULL,
    product_name VARCHAR(255) NOT NULL,
    unit_price NUMERIC(12, 2) NOT NULL CHECK (unit_price >= 0),
    quantity INT NOT NULL CHECK (quantity > 0),
    line_total NUMERIC(12, 2) GENERATED ALWAYS AS (unit_price * quantity) STORED
);

CREATE TABLE ecommerce.payments (
    id BIGINT DEFAULT nextval('ecommerce.payments_id_seq') PRIMARY KEY,
    order_id BIGINT NOT NULL REFERENCES ecommerce.orders(id) ON DELETE RESTRICT,
    method VARCHAR(50) NOT NULL CHECK (method IN ('credit_card','debit_card','paypal','bank_transfer','crypto','gift_card')),
    status VARCHAR(50) NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','completed','failed','refunded')),
    amount NUMERIC(12, 2) NOT NULL CHECK (amount > 0),
    transaction_id VARCHAR(255) UNIQUE,
    paid_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.reviews (
    id BIGINT DEFAULT nextval('ecommerce.reviews_id_seq') PRIMARY KEY,
    product_id BIGINT NOT NULL REFERENCES ecommerce.products(id) ON DELETE CASCADE,
    user_id BIGINT NOT NULL REFERENCES ecommerce.users(id) ON DELETE CASCADE,
    rating SMALLINT NOT NULL CHECK (rating BETWEEN 1 AND 5),
    title VARCHAR(255),
    body TEXT,
    is_verified_purchase BOOLEAN NOT NULL DEFAULT FALSE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_user_product_review UNIQUE (user_id, product_id)
);

