CREATE OR REPLACE VIEW ecommerce.v_product_summary AS
SELECT
    p.id,
    p.name,
    p.slug,
    p.price,
    p.stock_quantity,
    p.sku,
    p.is_active,
    c.name AS category_name,
    ROUND(AVG(r.rating), 2) AS avg_rating,
    COUNT(r.id) AS review_count
FROM ecommerce.products p
LEFT JOIN ecommerce.categories c ON c.id = p.category_id
LEFT JOIN ecommerce.reviews r ON r.product_id = p.id
GROUP BY p.id, c.name;

CREATE OR REPLACE VIEW ecommerce.v_order_summary AS
SELECT
    o.id AS order_id,
    o.status,
    o.created_at,
    o.total,
    u.id AS user_id,
    u.email,
    u.first_name,
    u.last_name,
    COUNT(oi.id) AS item_count,
    p.status AS payment_status,
    p.method AS payment_method
FROM ecommerce.orders o
JOIN ecommerce.users u ON u.id = o.user_id
LEFT JOIN ecommerce.order_items oi ON oi.order_id = o.id
LEFT JOIN ecommerce.payments p ON p.order_id = o.id
GROUP BY o.id, u.id, p.status, p.method;

CREATE OR REPLACE VIEW ecommerce.v_cart_details AS
SELECT
    c.id AS cart_id,
    c.user_id,
    c.session_id,
    ci.id AS cart_item_id,
    pr.id AS product_id,
    pr.name AS product_name,
    pr.price AS unit_price,
    ci.quantity,
    (pr.price * ci.quantity) AS line_total
FROM ecommerce.carts c
JOIN ecommerce.cart_items ci ON ci.cart_id = c.id
JOIN ecommerce.products pr ON pr.id = ci.product_id;
